          ProtoAdapter.FLOAT.encodeWithTag(writer, 20, value.min_p)
        }
        if (!value.presence_penalty.equals(0f)) {
          ProtoAdapter.FLOAT.encodeWithTag(writer, 19, value.presence_penalty)
        }
        if (!value.frequency_penalty.equals(0f)) {
